import React from 'react';
import './App.css';

function Dashboard() {
  return (
    <div className="dashboard">
      <h2>Dashboard</h2>
      <p>Welcome to your learning dashboard. Select a module to begin.</p>
    </div>
  );
}

export default Dashboard;
